package "Post Filtering Feature" {
  interface IXmlSerializable {
  }

  interface IEnumerable {
  }

  class FormFilterGroup {
    + GroupFilter: FilterGroup {getter, setter}
  }

  class FilterItem {
    + constructor()
    + constructor(Regex)
    + IsMatch(Post): bool
  }

  class FilterGroup {
    - IList<FilterItem>
    + Name: string {getter, setter}
    + constructor()
    + AddItem(FilterItem)
    + RemoveItem(FilterItem)
    + IsMatch(Post): bool
  }

  class PostFilter {
    + FilterGroups: IList<FilterGroup> {getter, setter}
    + constructor()
    + AddGroup(FilterGroup)
    + RemoveGroup(FilterGroup)
    + Save()
  }

  class FormPostFilterSettings {
    + PostFilter: PostFilter {getter, setter}
  }
}

interface IXmlSerializable_Global as "IXmlSerializable" {
  + ReadXml(XmlReader reader): void
  + WriteXml(XmlWriter writer): void
}

interface IEnumerable_Global as "IEnumerable" {
  + GetEnumerator(): IEnumerator
}

